const milestones = $input.all().map(i => i.json);
const atRisk = milestones.filter(m => m.days_until_due <= 14 && m.status !== 'completed');
const blocked = milestones.filter(m => m.status === 'blocked');

// Auto-update at_risk status
const updates = milestones.filter(m => m.days_until_due <= 14 && m.status === 'pending')
  .map(m => m.milestone_name);

const completed = milestones.filter(m => m.status === 'completed').length;
const total = milestones.length;

return [{ json: {
  total_milestones: total,
  completed,
  at_risk: atRisk.length,
  blocked: blocked.length,
  at_risk_items: atRisk,
  blocked_items: blocked,
  auto_flag: updates
}}];

